#!/bin/bash
# Tester la robustesse d'une fonction avec des entrées aléatoires

# Générer des entrées de fuzzing
fuzz_string() {
    local type=${1:-any}
    case $type in
        empty)   echo "" ;;
        null)    echo -e "\0" ;;
        space)   echo "   " ;;
        newline) echo -e "a\nb\nc" ;;
        special) echo '!@#$%^&*()[]{}|\;:",./<>?' ;;
        unicode) echo "héllo wörld 日本語" ;;
        long)    head -c 10000 /dev/urandom | tr -dc 'a-zA-Z' ;;
        inject)  echo "'; rm -rf /tmp/test; echo '" ;;
        *) openssl rand -base64 16 ;;
    esac
}

# Tester une fonction
test_robustness() {
    local func=$1
    local types=(empty space special unicode long inject)

    echo "Test de robustesse : $func"
    for type in "${types[@]}"; do
        local input
        input=$(fuzz_string "$type")
        if $func "$input" > /dev/null 2>&1; then
            echo "  [OK] $type"
        else
            echo "  [KO] $type — exit $?"
        fi
    done
}

# Exemple de fonction à tester
process_input() {
    local input=$1
    [ -z "$input" ] && return 1  # rejeter l'entrée vide
    echo "Traité : ${input:0:50}"  # tronquer à 50 chars
    return 0
}

test_robustness process_input
